INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (0.2, 13020018, "nyx_idle_normal", 0.2, "nyx_302_yuni_02", 0, 111031, 1, "", 3, 302);
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 13020019, "", "", "だが怪我の功名、\n探していた部品を\n偶然にも発見できた", 10, 111031, "", "", 11, 302);
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 13020020, "", "", "", "", 5, "", "", 93, 302);
