INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 13020023, "", "", "ふむ…これは僥倖\nかくなる上は再び\n潜航してみるか…", 10, 111031, "", "", 11, 302);
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 13020024, "", "", "", "", 0, "", "", 91, 302);
